const stdout = $json.stdout || $json.data || '';
let payload;
try {
  payload = JSON.parse(stdout);
} catch (error) {
  throw new Error(`social-package stdout was not valid JSON: ${error.message}`);
}
return [{ json: payload }];

const payload = $json;
const errors = [];
const isObject = (value) => value !== null && typeof value === 'object' && !Array.isArray(value);
if (!isObject(payload.contract)) errors.push('contract must be an object');
if (payload.contract?.name !== 'artnouveau.social_package') errors.push('contract.name must be artnouveau.social_package');
if (payload.contract?.version !== 1) errors.push('contract.version must be 1');
if (payload.contract?.kind !== 'read_only_social_handoff') errors.push('contract.kind must be read_only_social_handoff');
if (!payload.slug) errors.push('slug is required');
if (!payload.queue_status) errors.push('queue_status is required');
if (!isObject(payload.caption)) errors.push('caption must be an object');
if (!isObject(payload.media)) errors.push('media must be an object');
if (!isObject(payload.links)) errors.push('links must be an object');
if (errors.length) {
  throw new Error(`Invalid social-package handoff: ${errors.join('; ')}`);
}
return [{ json: payload }];

const payload = $json;
const review = {
  prototype: 'local_n8n_social_review_stop',
  contract: payload.contract ? `${payload.contract.name}@${payload.contract.version}` : 'unknown',
  status: payload.queue_status || 'unknown',
  slug: payload.slug || '',
  readiness: payload.readiness || {},
  locale_status: payload.locale_status || {},
  preview_paths: payload.links?.preview_paths || {},
  reasons: payload.reasons || []
};
return [{ json: review }];
